}))"}

{"code":"import json

papers_file = locals()['var_function-call-4873793932197398139']
citations_file = locals()['var_function-call-1796445934379117253']

with open(papers_file, 'r') as f:
    papers = json.load(f)
with open(citations_file, 'r') as f:
    citations = json.load(f)

food_titles = []
for paper in papers:
    if 'food' in paper['text'].lower():
        food_titles.append(paper['filename'].replace('.txt', ''))

total_citations = 0
for cit in citations:
    if cit['title'] in food_titles:
        total_citations += int(cit['citation_count'])

print("__RESULT__:")
print(json.dumps({
    "total_papers": len(papers),
    "food_papers_count": len(food_titles),
    "food_titles": food_titles,
    "total_citations": total_citations
}))"}

